// Total: 51 states, 124 cities

// Get all cities as a flat array
export function getAllCities(): GeoCity[] {
  return STATES.flatMap(state => state.cities)
}

// Get a state by abbreviation
export function getStateByAbbr(abbr: string): GeoState | undefined {
  return STATES.find(s => s.abbr.toLowerCase() === abbr.toLowerCase())
}

// Get a state by slug
export function getStateBySlug(slug: string): GeoState | undefined {
  return STATES.find(s => s.slug === slug)
}

// Get a city by its slug (e.g. "philadelphia-pa")
export function getCityBySlug(slug: string): GeoCity | undefined {
  for (const state of STATES) {
    const city = state.cities.find(c => c.slug === slug)
    if (city) return city
  }
  return undefined
}

// Get cities for a specific state
export function getCitiesByState(stateAbbr: string): GeoCity[] {
  const state = getStateByAbbr(stateAbbr)
  return state?.cities ?? []
}
